import re
from dataclasses import dataclass, field
from typing import ClassVar, Dict, List, Set

from .enums import DS2Version, APLocationType
from .items import item_dictionary

CHR = APLocationType.ItemLotParam2_Chr
OTHER = APLocationType.ItemLotParam2_Other
SHOP = APLocationType.ShopLineupParam

VANILLA = DS2Version.VANILLA
SOTFS = DS2Version.SOTFS


@dataclass
class LocationData:
    location_type: APLocationType
    """TODO"""

    ds2_id: int
    """TODO"""

    name: str
    """The Archipelago name for this location."""

    version: DS2Version = None
    """The version that this location is part of."""

    shop_price: float = 0
    """TODO"""

    missable: bool = False
    """Whether this location can become in some way unreachable by the player."""

    keep_original_item: bool = False
    """Whether this location will keep it's original item."""

    original_item_name: str = field(init=False)
    """The item that is found at this location in the non randomized game."""

    address: int = field(init=False)
    """The Archipelago address for this location."""

    next_address: ClassVar[int] = 1
    """The next address to be used when creating a new location."""

    @property
    def is_shop(self):
        return self.location_type == APLocationType.ShopLineupParam

    @property
    def is_event(self):
        return self.address == None

    def __post_init__(self):
        if self.ds2_id == None:
            self.address = None
            self.original_item_name = None
            return

        # make sure all enemy drops are missable because enemy drops
        # disappear if the player dies without picking them up
        if self.location_type == APLocationType.ItemLotParam2_Chr:
            self.missable = True

        # https://gist.github.com/nex3/5bfbc00cc272c80cdb94d292f2aa87ee
        match = re.match(r'^(.*?): (.*?)(?: - .*?)?$', self.name)
        assert match, f"Invalid location name format: {self.name}"

        _, item_name = match.groups()
        self.original_item_name = item_name

        self.address = LocationData.next_address
        LocationData.next_address += 1


